import{_ as d,c as e,o,a3 as r}from"./chunks/framework.CTM16EAR.js";const _=JSON.parse('{"title":"SOP：帮助页（VitePress）跳转与 Cloudflare","description":"","frontmatter":{"search":false},"headers":[],"relativePath":"dev-log/SOP/help-docs-cloudflare.md","filePath":"dev-log/SOP/help-docs-cloudflare.md","lastUpdated":1775720707000}'),a={name:"dev-log/SOP/help-docs-cloudflare.md"};function c(s,t,l,i,n,h){return o(),e("div",null,t[0]||(t[0]=[r('<h1 id="sop-帮助页-vitepress-跳转与-cloudflare" tabindex="-1">SOP：帮助页（VitePress）跳转与 Cloudflare <a class="header-anchor" href="#sop-帮助页-vitepress-跳转与-cloudflare" aria-label="Permalink to &quot;SOP：帮助页（VitePress）跳转与 Cloudflare&quot;">​</a></h1><p>与 <a href="./docs-deployment.html">docs-deployment.md</a>（部署与本地开发口径）互为补充：本文侧重 <strong>线上点「帮助」应跳到哪里</strong> 及 <strong>Cloudflare 操作步骤</strong>。</p><h2 id="_1-目的与适用范围" tabindex="-1">1. 目的与适用范围 <a class="header-anchor" href="#_1-目的与适用范围" aria-label="Permalink to &quot;1. 目的与适用范围&quot;">​</a></h2><ul><li><strong>目的</strong>：主应用点「帮助」时，浏览器跳到<strong>正确</strong>的 VitePress 文档 URL（独立子域或主站子路径）。</li><li><strong>适用</strong>：Pomotention Web/PWA（Cloudflare Pages）、本地开发；桌面端行为见 <strong>§7</strong>。</li></ul><h2 id="_2-前置知识-一页" tabindex="-1">2. 前置知识（一页） <a class="header-anchor" href="#_2-前置知识-一页" aria-label="Permalink to &quot;2. 前置知识（一页）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>说明</th></tr></thead><tbody><tr><td>触发点</td><td>菜单「帮助」、<code>/help</code> 路由 → <code>navigateToBuiltDocs()</code></td></tr><tr><td>Web 逻辑</td><td><code>src/composables/useDocsUrl.ts</code>：<code>VITE_HELP_DOCS_URL</code> 有值则整页跳外链，否则跳 <strong>同源</strong> <code>{BASE_URL}docs-app/</code></td></tr><tr><td>Tauri 逻辑</td><td><strong>不读</strong> <code>VITE_HELP_DOCS_URL</code>，只跳 <code>{BASE_URL}docs-app/</code>（打包内须有文件）</td></tr><tr><td><code>BASE_URL</code></td><td>来自 <code>VITE_APP_BASE</code>（Vite <code>base</code>），根部署多为 <code>/</code></td></tr></tbody></table><h2 id="_3-先选方案" tabindex="-1">3. 先选方案 <a class="header-anchor" href="#_3-先选方案" aria-label="Permalink to &quot;3. 先选方案&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方案</th><th>何时用</th><th>主应用要做什么</th><th>文档站要做什么</th></tr></thead><tbody><tr><td><strong>A. 外链文档站</strong></td><td>文档单独 Pages 项目（如 <code>*.pages.dev</code>）</td><td>构建时设 <code>VITE_HELP_DOCS_URL</code></td><td><code>VITEPRESS_BASE=/</code>（子域根）</td></tr><tr><td><strong>B. 同源 docs-app</strong></td><td>帮助与主站同域</td><td><code>pnpm build:with-docs</code> 部署完整 <code>dist</code></td><td>由 <code>run-docs-for-app</code> + sync 进主站，不需单独对外文档 URL</td></tr></tbody></table><h2 id="_4-sop-a-web-跳到独立文档站" tabindex="-1">4. SOP-A：Web 跳到独立文档站 <a class="header-anchor" href="#_4-sop-a-web-跳到独立文档站" aria-label="Permalink to &quot;4. SOP-A：Web 跳到独立文档站&quot;">​</a></h2><p><strong>目标</strong>：点帮助打开 <code>https://&lt;你的文档域&gt;/</code>，不依赖主站上的 <code>/docs-app/</code> 目录。</p><table tabindex="0"><thead><tr><th>步骤</th><th>操作</th><th>通过条件</th></tr></thead><tbody><tr><td>A1</td><td>打开 <strong>主应用</strong> Cloudflare Pages 项目</td><td>对应主站域名（如 <code>pomotention.pages.dev</code>）</td></tr><tr><td>A2</td><td>Settings → Environment variables</td><td>Production（及需要的 Preview）</td></tr><tr><td>A3</td><td>新增：<code>VITE_HELP_DOCS_URL</code> = <code>https://&lt;文档域&gt;/</code></td><td>值与浏览器能打开的文档首页一致</td></tr><tr><td>A4</td><td>触发 <strong>重新构建并部署</strong></td><td>仅改变量不重 build 无效</td></tr><tr><td>A5</td><td>打开主站 → 点「帮助」</td><td>地址栏变为文档域，且文档页正常（非白屏）</td></tr><tr><td>A6</td><td>（可选）仓库根 <code>.env.development</code> 写同一变量</td><td>本地 dev 行为与线上一致</td></tr></tbody></table><p><strong>文档站构建（Cloudflare 文档项目）</strong></p><table tabindex="0"><thead><tr><th>步骤</th><th>操作</th></tr></thead><tbody><tr><td>D1</td><td>构建命令中设置环境变量 <code>VITEPRESS_BASE=/</code></td></tr><tr><td>D2</td><td>执行 <code>vitepress build</code>（或仓库 <code>docs</code> 下等价脚本）</td></tr><tr><td>D3</td><td>部署产物；浏览器直接打开文档根 URL 自检</td></tr></tbody></table><p><strong>常见失败</strong></p><ul><li>主应用未重部署 → 仍跳主站 <code>/docs-app/</code>。</li><li>文档站仍用默认 <code>base</code>（如 <code>/pomotention/</code>）却挂在子域根 → 资源 404 / 白屏。</li></ul><h2 id="_5-sop-b-主站同源嵌入-docs-app" tabindex="-1">5. SOP-B：主站同源嵌入 docs-app <a class="header-anchor" href="#_5-sop-b-主站同源嵌入-docs-app" aria-label="Permalink to &quot;5. SOP-B：主站同源嵌入 docs-app&quot;">​</a></h2><p><strong>目标</strong>：<code>https://&lt;主站&gt;/docs-app/</code>（或 <code>/&lt;VITE_APP_BASE&gt;/docs-app/</code>）可访问。</p><table tabindex="0"><thead><tr><th>步骤</th><th>操作</th><th>通过条件</th></tr></thead><tbody><tr><td>B1</td><td>主站 Pages <strong>Build command</strong> 使用 <code>pnpm build:with-docs</code>（或等价的 build → sync → vite build）</td><td><code>pnpm install</code> 在仓库根</td></tr><tr><td>B2</td><td>部署输出目录包含 <code>docs-app/</code></td><td>浏览器直接打开上述 URL 非 404</td></tr><tr><td>B3</td><td><strong>不</strong>设置 <code>VITE_HELP_DOCS_URL</code>（或置空）</td><td>点帮助跳同源路径</td></tr></tbody></table><p><strong>注意</strong>：<code>VITE_APP_BASE</code> 非空时，文档须用 <code>scripts/run-docs-for-app.mjs</code> 生成相同前缀下的 <code>docs-app</code>。</p><h2 id="_6-排查速查" tabindex="-1">6. 排查速查 <a class="header-anchor" href="#_6-排查速查" aria-label="Permalink to &quot;6. 排查速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>优先查</th></tr></thead><tbody><tr><td>点帮助进主站 <code>/docs-app/</code> 且 404</td><td>主站是否只跑了 <code>pnpm build</code>；改 <strong>SOP-B</strong> 或改 <strong>SOP-A</strong></td></tr><tr><td>文档子域浏览器能开，帮助仍进主站</td><td>主应用是否已设 <code>VITE_HELP_DOCS_URL</code> 并重部署</td></tr><tr><td>跳进文档域但白屏/样式炸</td><td>文档构建是否 <code>VITEPRESS_BASE=/</code> 与 URL 路径一致</td></tr><tr><td>设置里「文档站」检测失败</td><td><code>src/views/SettingView.vue</code> 中 <code>NET_DOCS</code> 是否与实际域名一致（如 <code>doc</code> vs <code>docs</code>）</td></tr></tbody></table><h2 id="_7-桌面端-tauri" tabindex="-1">7. 桌面端（Tauri） <a class="header-anchor" href="#_7-桌面端-tauri" aria-label="Permalink to &quot;7. 桌面端（Tauri）&quot;">​</a></h2><ul><li>帮助始终：<code>{origin}{BASE_URL}docs-app/</code>。</li><li><code>VITE_HELP_DOCS_URL</code> <strong>不生效</strong>。</li><li>若要桌面也跳外链：<strong>须改代码</strong>（本 SOP 不覆盖）。</li></ul><h2 id="_8-可选维护" tabindex="-1">8. 可选维护 <a class="header-anchor" href="#_8-可选维护" aria-label="Permalink to &quot;8. 可选维护&quot;">​</a></h2><ul><li>将 <code>NET_DOCS</code> 改成与生产文档 URL 一致，避免网络检测误导。</li><li>仓库内可维护 <code>.env.production.example</code> 列出 <code>VITE_HELP_DOCS_URL</code>（不提交密钥即可）。</li></ul><h2 id="_9-代码参考路径" tabindex="-1">9. 代码参考路径 <a class="header-anchor" href="#_9-代码参考路径" aria-label="Permalink to &quot;9. 代码参考路径&quot;">​</a></h2><ul><li>跳转：<code>src/composables/useDocsUrl.ts</code></li><li>路由：<code>/help</code> → <code>src/router/index.ts</code></li><li>菜单：<code>src/views/MainLayout.vue</code></li><li>VitePress <code>base</code>：<code>docs/.vitepress/config.mts</code>（<code>process.env.VITEPRESS_BASE</code>）</li></ul>',27)]))}const u=d(a,[["render",c]]);export{_ as __pageData,u as default};
